Для решения этой задачи, вам потребуется использовать функции из Windows API: `OpenProcess`, `ReadProcessMemory`, `WriteProcessMemory`, и `CloseHandle`. Обратите внимание, что для работы с процессами требуются права администратора. Вот базовый пример программы, которая выполняет задачу:

```cpp
#include <Windows.h>
#include <TlHelp32.h>
#include <iostream>
#include <vector>

DWORD FindProcessId(const std::string& processName) {
    PROCESSENTRY32 processInfo;
    processInfo.dwSize = sizeof(processInfo);

    HANDLE processesSnapshot = CreateToolhelp32Snapshot(TH32CS_SNAPPROCESS, NULL);
    if (processesSnapshot == INVALID_HANDLE_VALUE)
        return 0;

    Process32First(processesSnapshot, &processInfo);
    if (!processName.compare(processInfo.szExeFile)) {
        CloseHandle(processesSnapshot);
        return processInfo.th32ProcessID;
    }

    while (Process32Next(processesSnapshot, &processInfo)) {
        if (!processName.compare(processInfo.szExeFile)) {
            CloseHandle(processesSnapshot);
            return processInfo.th32ProcessID;
        }
    }

    CloseHandle(processesSnapshot);
    return 0;
}

bool PatchProcess(DWORD processID) {
    HANDLE hProcess = OpenProcess(PROCESS_ALL_ACCESS, FALSE, processID);
    if (hProcess == NULL) {
        std::cout << "Failed to open the target process.\n";
        return false;
    }

    std::cout << "Successfully opened the process.\n";

    // Signature to search for
    BYTE signatureBytes[] = { 0x85, 0xC0, 0x74, 0x57, 0x5F, 0xB8, 0x01 };
    BYTE patch[] = { 0x00 }; // Patch value
    SIZE_T bytesRead;
    std::vector<BYTE> buffer(1024 * 1024); // 1MB buffer

    for (DWORD i = 0x00400000; i < 0x7FFFFFFF; i += buffer.size()) {
        ReadProcessMemory(hProcess, (LPCVOID)i, buffer.data(), buffer.size(), &bytesRead);

        for (size_t j = 0; j < bytesRead - sizeof(signatureBytes); ++j) {
            if (memcmp(buffer.data() + j, signatureBytes, sizeof(signatureBytes)) == 0) {
                std::cout << "Signature found at: " << std::hex << (i + j) << std::endl;
                DWORD oldProtect, bck;
                VirtualProtectEx(hProcess, (LPVOID)(i + j + sizeof(signatureBytes) - 1), sizeof(patch), PAGE_EXECUTE_READWRITE, &oldProtect);
                WriteProcessMemory(hProcess, (LPVOID)(i + j + sizeof(signatureBytes) - 1), patch, sizeof(patch), NULL);
                VirtualProtectEx(hProcess, (LPVOID)(i + j + sizeof(signatureBytes) - 1), sizeof(patch), oldProtect, &bck);
                std::cout << "Patched successfully.\n";
                CloseHandle(hProcess);
                return true;
            }
        }
    }

    std::cout << "Signature not found.\n";
    CloseHandle(hProcess);
    return false;
}

int main() {
    const std::string processName = "L2.exe";
    DWORD processID = FindProcessId(processName);

    if (processID == 0) {
        std::cout << "Process " << processName << " not found.\n";
        return 1;
    }

    std::cout << "Process ID: " << processID << std::endl;

    if (PatchProcess(processID)) {
        std::cout << "Operation completed successfully.\n";
    } else {
        std::cout << "Operation failed.\n";
    }

    return 0;
}
```

Обратите внимание:

1. Вам нужно включить соответствующий флаг `COMPATIBILITY_ADMINISTRATOR` и запускать программу от имени администратора, чтобы `OpenProcess` успешно выполнила свою функцию.
2. Этот код использует очень базовый способ поиска последовательности в памяти процесса. В большом процессе это может быть медленным.
3. Использован простой подход к защите памяти с `VirtualProtectEx` перед записью изменений.
4. Использование магических чисел (как `0x00400000` и `0x7FFFFFFF`) для обозначения диапазона адресов для сканирования может не подойти для всех процессов. Настоятельно рекомендуется разработать более надежный метод для определения этих границ.

Также, прежде чем искать и изменять память других процессов, убедитесь, что это не нарушает условий использования программного обеспечения и местных законов.

Чтобы улучшить код и сделать его более эффективным и универсальным, можно применить некоторые изменения, такие как динамическое определение диапазона памяти процесса, оптимизацию сканирования памяти, и применение более корректной обработки ошибок. Вот обновленный пример программы:

```cpp
#include <Windows.h>
#include <TlHelp32.h>
#include <iostream>
#include <vector>

DWORD FindProcessId(const std::string& processName) {
    PROCESSENTRY32 processInfo;
    processInfo.dwSize = sizeof(processInfo);

    HANDLE processesSnapshot = CreateToolhelp32Snapshot(TH32CS_SNAPPROCESS, NULL);
    if (processesSnapshot == INVALID_HANDLE_VALUE)
        return 0;

    Process32First(processesSnapshot, &processInfo);
    if (processName == processInfo.szExeFile) {
        CloseHandle(processesSnapshot);
        return processInfo.th32ProcessID;
    }

    while (Process32Next(processesSnapshot, &processInfo)) {
        if (processName == processInfo.szExeFile) {
            CloseHandle(processesSnapshot);
            return processInfo.th32ProcessID;
        }
    }

    CloseHandle(processesSnapshot);
    return 0;
}

std::pair<void*, void*> GetProcessBounds(DWORD processId) {
    MEMORY_BASIC_INFORMATION mbi;
    std::pair<void*, void*> bounds = {0, 0};
    unsigned char *addr = nullptr;
    HANDLE process = OpenProcess(PROCESS_QUERY_INFORMATION | PROCESS_VM_READ, FALSE, processId);
    if (process == NULL) return bounds;
    while (sizeof(mbi) == VirtualQueryEx(process, addr, &mbi, sizeof(mbi))) {
        if (mbi.State == MEM_COMMIT) {
            if (!bounds.first) bounds.first = mbi.BaseAddress;
            bounds.second = (void*)((uintptr_t)mbi.BaseAddress + mbi.RegionSize);
        }
        addr += mbi.RegionSize;
    }
    CloseHandle(process);
    return bounds;
}

bool PatchProcess(DWORD processID) {
    auto [startAddress, endAddress] = GetProcessBounds(processID);
    if (startAddress == nullptr || endAddress == nullptr) {
        std::cout << "Failed to determine the process memory bounds.\n";
        return false;
    }

    HANDLE hProcess = OpenProcess(PROCESS_ALL_ACCESS, FALSE, processID);
    if (hProcess == NULL) {
        std::cout << "Failed to open the target process.\n";
        return false;
    }

    BYTE signatureBytes[] = { 0x85, 0xC0, 0x74, 0x57, 0x5F, 0xB8, 0x01 };
    BYTE patch[] = { 0x00 }; // Patch value
    SIZE_T bytesRead;
    const size_t bufferSize = 4096; // Considering page size 
    std::vector<BYTE> buffer(bufferSize);

    for (unsigned char* addr = static_cast<unsigned char*>(startAddress); addr < endAddress; addr += bufferSize) {
        ReadProcessMemory(hProcess, addr, buffer.data(), bufferSize, &bytesRead);
        for (size_t j = 0; j < bytesRead - sizeof(signatureBytes); ++j) {
            if (memcmp(buffer.data() + j, signatureBytes, sizeof(signatureBytes)) == 0) {
                std::cout << "Signature found at: " << std::hex << (uintptr_t)addr + j << std::endl;
                DWORD oldProtect;
                if (VirtualProtectEx(hProcess, addr + j + sizeof(signatureBytes) - 1, sizeof(patch), PAGE_EXECUTE_READWRITE, &oldProtect)) {
                    WriteProcessMemory(hProcess, addr + j + sizeof(signatureBytes) - 1, patch, sizeof(patch), NULL);
                    VirtualProtectEx(hProcess, addr + j + sizeof(signatureBytes) - 1, sizeof(patch), oldProtect, &oldProtect);
                    std::cout << "Patched successfully.\n";
                    CloseHandle(hProcess);
                    return true;
                }
            }
        }
    }

    std::cout << "Signature not found in the given process.\n";
    CloseHandle(hProcess);
    return false;
}

int main() {
    const std::string processName = "L2.exe";
    DWORD processID = FindProcessId(processName);

    if (processID == 0) {
        std::cout << "Process " << processName << " not found.\n";
        return 1;
    }

    std::cout << "Process ID: " << processID << std::endl;

    if (PatchProcess(processID)) {
        std::cout << "Operation completed successfully.\n";
    } else {
        std::cout << "Operation failed.\n";
    }

    return 0;
}
```

В этой версии программы были применены следующие улучшения:

1. **Определение границ процесса:** Вместо жестко заданных значений для сканирования, функция `GetProcessBounds` определяет динамические границы памяти с помощью `VirtualQueryEx`.
2. **Изменение размера буфера:** Размер буфера установлен в соответствии с размером страницы памяти для оптимизации чтения.
3. **Более точная работа с памятью:** Вместо магических чисел используются конкретные адреса начала и конца памяти, полученные из `GetProcessBounds`, что делает сканирование более точным и универсальным.
4. **Обработка ошибок:** Добавлена более корректная обработка ошибок и проверка результата операций с памятью.

Эти изменения помогут улучшить эффективность, точность и универсальность программы.

Если вы планируете инжектировать этот код как DLL в другой процесс, использование `std::cout` действительно становится бесполезным, так как вы не увидите вывод в консоли вызывающего процесса. Взаимодействие с пользователем или логирование в таком случае можно осуществлять через другие методы, например, вывод в файл лога или использование специализированных инструментов для логирования, которые поддерживают работу с DLL. 

Вот пример, как можно модифицировать программу для вывода в файл вместо использования `std::cout`:

