std::ofstream logFile("patcher_log.txt", std::ios::out | std::ios::app);

// Функции и основная программа остаются без изменений

bool PatchProcess(DWORD processID) {
    auto [startAddress, endAddress] = GetProcessBounds(processID);
    if (startAddress == nullptr || endAddress == nullptr) {
        logFile << "Failed to determine the process memory bounds.\n";
        return false;
